def load_native_for_proba(model_uri: str):
    pyfunc_model = load_pyfunc(model_uri)
    flvs = pyfunc_model.metadata.flavors

    if "sklearn" in flvs:
        return mlflow.sklearn.load_model(model_uri)
    elif "lightgbm" in flvs:
        return mlflow.lightgbm.load_model(model_uri)
    else:
        raise ValueError(f"Unknown flavor in {flvs}")
```

